class Solution:
    def partition(self, head: Optional[ListNode], x: int) -> Optional[ListNode]:
        small = large = ListNode(0); s, l = small, large
        while head:
            if head.val < x:
                s.next = head; s = s.next
            else:
                l.next = head; l = l.next
            head = head.next
        l.next = None; s.next = large.next
        return small.next

