class Solution {
public:
    ListNode* partition(ListNode* head, int x) {
        ListNode sd(0), ld(0), *s=&sd, *l=&ld;
        for (ListNode* p=head; p; p=p->next) {
            if (p->val < x) { s->next=p; s=s->next; }
            else { l->next=p; l=l->next; }
        }
        l->next=nullptr; s->next=ld.next;
        return sd.next;
    }
};
